import redis
import sys

class AdvancedCacheClient:
    def __init__(self, host='localhost', port=6379, db=0):
        self.redis_client = redis.Redis(host=host, port=port, db=db, decode_responses=True)
    
    def execute_lua_script(self, script_code, keys=None, args=None):
        """
        Execute Lua script with user-provided code and parameters
        
        Args:
            script_code (str): Lua script code to execute
            keys (list): List of Redis key names to use in script
            args (list): List of arguments to pass to the script
            
        Returns:
            Result of script execution
        """
        try:
            # Execute the Lua script
            result = self.redis_client.eval(script_code, keys, args)
            return result
        except Exception as e:
            print(f"Error executing Lua script: {e}")
            return None
    
    def create_cache_operation(self, operation_type, key, value=None, ttl=None):
        """
        Create dynamic cache operations using Lua scripts
        
        Args:
            operation_type (str): Type of operation (set, get, update, delete)
            key (str): Redis key
            value (str): Value to set (for set operations)
            ttl (int): Time-to-live in seconds
            
        Returns:
            Result of the operation
        """
        scripts = {
            'set': '''
                redis.call('SET', KEYS[1], ARGV[1])
                if ARGV[2] ~= nil then
                    redis.call('EXPIRE', KEYS[1], ARGV[2])
                end
                return redis.call('GET', KEYS[1])
            ''',
            'get': '''
                return redis.call('GET', KEYS[1])
            ''',
            'update': '''
                local current_value = redis.call('GET', KEYS[1])
                if current_value then
                    local new_value = current_value .. ARGV[1]
                    redis.call('SET', KEYS[1], new_value)
                    return new_value
                end
                return nil
            ''',
            'delete': '''
                return redis.call('DEL', KEYS[1])
            ''',
            'increment': '''
                return redis.call('INCR', KEYS[1])
            ''',
            'conditional_set': '''
                if redis.call('GET', KEYS[1]) == ARGV[1] then
                    redis.call('SET', KEYS[1], ARGV[2])
                    return 1
                else
                    return 0
                end
            '''
        }
        
        script = scripts.get(operation_type)
        if script:
            keys = [key] if key else []
            args = [value, ttl] if value and ttl else [value] if value else []
            return self.execute_lua_script(script, keys, args)
        else:
            print("Unsupported operation type")
            return None

